from flask import Flask, request, jsonify, g
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from werkzeug.security import generate_password_hash, check_password_hash
from itsdangerous import TimedJSONWebSignatureSerializer as Serializer
from functools import wraps
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = os.urandom(24)
app.config['TOKEN_EXPIRATION'] = 3600  # Token valid for 1 hour

limiter = Limiter(app, key_func=get_remote_address)

users_db = {
    "user1": generate_password_hash("strongpassword1"),
    "user2": generate_password_hash("strongpassword2")
}

def generate_token(username):
    s = Serializer(app.config['SECRET_KEY'], expires_in=app.config['TOKEN_EXPIRATION'])
    return s.dumps({'username': username}).decode('utf-8')

def verify_token(token):
    s = Serializer(app.config['SECRET_KEY'])
    try:
        data = s.loads(token)
    except:
        return None
    return data['username']

def token_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('x-access-token')
        if not token:
            return jsonify({'message': 'Token is missing!'}), 401
        username = verify_token(token)
        if not username:
            return jsonify({'message': 'Token is invalid or expired!'}), 401
        g.user = username
        return f(*args, **kwargs)
    return decorated_function

@app.route('/login', methods=['POST'])
@limiter.limit("5 per minute")
def login():
    auth = request.authorization
    if not auth or not auth.username or not auth.password:
        return jsonify({'message': 'Could not verify'}), 401
    user_password_hash = users_db.get(auth.username)
    if user_password_hash and check_password_hash(user_password_hash, auth.password):
        token = generate_token(auth.username)
        return jsonify({'token': token})
    return jsonify({'message': 'Could not verify'}), 401

@app.route('/protected', methods=['GET'])
@token_required
def protected():
    return jsonify({'message': f'Hello, {g.user}!'})

